import { describe, it, expect, vi, beforeEach } from 'vitest'
import {
  toKanjiNumerals,
  drawVerticalColumn,
  drawVerticalBlock,
} from './verticalText'

// Canvas 2D コンテキストのモック
function makeCtx() {
  const calls: string[] = []
  const ctx = {
    save: vi.fn(() => calls.push('save')),
    restore: vi.fn(() => calls.push('restore')),
    translate: vi.fn(),
    rotate: vi.fn(),
    fillText: vi.fn(),
    textAlign: '',
    textBaseline: '',
    _calls: calls,
  }
  return ctx as unknown as CanvasRenderingContext2D & { _calls: string[] }
}

// ─── toKanjiNumerals ──────────────────────────────────────────────────────────

describe('toKanjiNumerals', () => {
  it('アラビア数字を漢数字に変換する', () => {
    expect(toKanjiNumerals('123')).toBe('一二三')
    expect(toKanjiNumerals('0')).toBe('〇')
    expect(toKanjiNumerals('9876543210')).toBe('九八七六五四三二一〇')
  })

